// Order CRUD operations
const createOrder = async (req, res) => {
  try {
    const { user_id, items } = req.body;
    
    if (!user_id || !items || !Array.isArray(items) || items.length === 0) {
      return res.status(400).json({ error: 'Invalid order data' });
    }

    const client = await pool.connect();
    
    try {
      await client.query('BEGIN');
      
      const orderResult = await client.query(
        'INSERT INTO orders (user_id, status) VALUES ($1, $2) RETURNING id',
        [user_id, 'pending']
      );
      
      const orderId = orderResult.rows[0].id;
      let total = 0;
      
      for (const item of items) {
        const productResult = await client.query(
          'SELECT price FROM products WHERE id = $1',
          [item.product_id]
        );
        
        if (productResult.rows.length === 0) {
          throw new Error('Product not found');
        }
        
        const itemTotal = productResult.rows[0].price * item.quantity;
        total += itemTotal;
        
        await client.query(
          'INSERT INTO order_items (order_id, product_id, quantity, price) VALUES ($1, $2, $3, $4)',
          [orderId, item.product_id, item.quantity, productResult.rows[0].price]
        );
      }
      
      await client.query('UPDATE orders SET total = $1 WHERE id = $2', [total, orderId]);
      await client.query('COMMIT');
      
      res.status(201).json({ id: orderId, user_id, total, status: 'pending' });
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
};

